// apps/frontend/composables/useAppImage.ts

/**
 * Backend'den gelen görsel yollarını (avatar, ürün, banner vb.) 
 * tam URL'ye dönüştürmek için kullanılan yardımcı composable.
 */
export const useAppImage = () => {
  const config = useRuntimeConfig();

  const resolveImageUrl = (path: string | null | undefined, type: 'avatar' | 'product' | 'banner' | 'general' = 'general') => {
    if (!path) {
      if (type === 'avatar') return '/images/default-avatar.png';
      return '/images/placeholder.png';
    }

    if (path.startsWith('http')) return path;

    const apiBase = config.public.apiBase || 'http://localhost:3001/api/v1';
    // Backend static paths (NestJS default static folder is 'uploads')
    const base = apiBase.replace('/api/v1', '');

    if (type === 'avatar') return `${base}/uploads/avatars/${path}`;
    if (type === 'product') return `${base}/uploads/products/${path}`;
    if (type === 'banner') return `${base}/uploads/banners/${path}`;

    return `${base}/uploads/${path}`;
  };

  return { resolveImageUrl };
};
<template>
  <div v-if="banners.length > 0" class="home-banner-slider relative w-full overflow-hidden group/slider bg-dark-950 rounded-[2.5rem] shadow-2xl">
    <!-- Banner Container -->
    <div
      class="banner-track flex transition-transform duration-[1000ms] cubic-bezier(0.16, 1, 0.3, 1)"
      :style="{ transform: `translateX(-${currentIndex * 100}%)` }"
    >
      <div
        v-for="(banner, index) in banners"
        :key="banner.id"
        class="banner-slide flex-shrink-0 w-full relative h-[400px] lg:h-[500px] cursor-pointer"
      >
        <!-- Image with slow zoom -->
        <img
          :src="resolveImageUrl(banner.imageUrl, 'banner')"
          class="w-full h-full object-cover transition-transform duration-[8000ms] ease-out"
          :style="{ transform: currentIndex === index ? 'scale(1.1)' : 'scale(1.0)' }"
        />

        <!-- Overlays -->
        <div class="absolute inset-0 bg-gradient-to-t from-dark-950/80 via-dark-950/20 to-transparent" />
        <div class="absolute inset-0 bg-gradient-to-r from-dark-950/40 via-transparent to-transparent" />

        <!-- Content -->
        <div class="absolute inset-0 flex items-center px-10 lg:px-20">
          <div class="max-w-2xl transform transition-all duration-1000" :class="currentIndex === index ? 'translate-x-0 opacity-100' : '-translate-x-12 opacity-0'">
            <span class="inline-flex items-center px-4 py-1.5 rounded-full bg-primary-600 text-white text-[10px] font-black uppercase tracking-[0.2em] mb-6">
              {{ banner.subtitle || 'Öne Çıkan' }}
            </span>
            <h2 class="text-4xl lg:text-7xl font-display font-black text-white italic leading-none mb-6 tracking-tighter shadow-sm">
              {{ banner.title }}
            </h2>
            <p class="text-gray-300 text-sm lg:text-lg font-medium max-w-lg mb-8 line-clamp-2">
              {{ banner.description }}
            </p>
            <button class="px-10 py-4 bg-white text-dark-950 rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-primary-500 hover:text-white transition-all duration-300 shadow-xl active:scale-95">
              Hemen Keşfet
            </button>
          </div>
        </div>
      </div>
    </div>

    <!-- Dots -->
    <div v-if="banners.length > 1" class="absolute bottom-10 left-10 lg:left-20 flex space-x-3 z-10">
       <button
         v-for="(_, index) in banners"
         :key="index"
         @click="currentIndex = index"
         class="h-1.5 rounded-full transition-all duration-500"
         :class="index === currentIndex ? 'w-12 bg-white' : 'w-3 bg-white/20 hover:bg-white/40'"
       />
    </div>
  </div>
</template>

<script setup lang="ts">
const props = defineProps<{
  ecosystem?: string;
}>();

const { resolveImageUrl } = useAppImage();
const banners = ref<any[]>([]);
const currentIndex = ref(0);

// Mock banners if none found
onMounted(async () => {
    // In a real app, fetch from API. 
    // Here we use mock data for "wow" effect if API is not yet seeded
    banners.value = [
      {
        id: '1',
        title: 'TICARI TAKASTA YENI NESIL',
        description: 'İşletmenizin atıl stoklarını saniyeler içinde nakde dönüştürün veya ihtiyacınız olan ürünlerle takas edin.',
        imageUrl: '/images/banner-1.jpg',
        subtitle: 'GELECEĞİN TİCARETİ'
      },
      {
        id: '2',
        title: 'PREMIUM AVANTAJLARI',
        description: 'BazarX Premium ile komisyon oranlarında %50 indirim ve VIP destek ayrıcalıklarından hemen faydalanın.',
        imageUrl: '/images/banner-2.jpg',
        subtitle: 'EXTREME FIRSAT'
      }
    ];

    setInterval(() => {
      currentIndex.value = (currentIndex.value + 1) % banners.value.length;
    }, 6000);
});
</script>

<style scoped>
.banner-track {
  will-change: transform;
}
</style>
<template>
  <div class="h-full space-y-12 pb-20">
    <!-- Premium Home Banner -->
    <LayoutHomeBanner ecosystem="BAZARX" />

    <!-- Feature Categories (Quick Access) -->
    <div class="grid grid-cols-2 lg:grid-cols-4 gap-6">
       <div v-for="(feat, index) in features" :key="index" 
            class="group bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-sm hover:shadow-2xl hover:-translate-y-2 transition-all duration-500 cursor-pointer overflow-hidden relative">
          <div class="absolute inset-0 bg-gradient-to-br from-primary-500/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
          <div class="relative z-10">
             <div class="w-14 h-14 bg-gray-50 rounded-2xl flex items-center justify-center mb-6 group-hover:bg-primary-600 transition-colors duration-500">
                <Icon :name="feat.icon" class="w-7 h-7 text-primary-600 group-hover:text-white transition-colors duration-500" />
             </div>
             <h3 class="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">{{ feat.label }}</h3>
             <p class="text-lg font-display font-black text-dark-950 italic leading-none">{{ feat.title }}</p>
          </div>
       </div>
    </div>

    <!-- Stats Grid (from previous design but improved) -->
    <div class="bg-dark-950 rounded-[3rem] p-12 lg:p-20 relative overflow-hidden shadow-2xl">
       <div class="absolute inset-0 bg-mesh opacity-10" />
       <div class="relative z-10 grid grid-cols-2 lg:grid-cols-4 gap-12">
          <div v-for="(stat, index) in stats" :key="index" class="text-center lg:text-left">
             <div class="text-[10px] font-black text-primary-500 uppercase tracking-[0.3em] mb-4">{{ stat.label }}</div>
             <div class="text-5xl lg:text-6xl font-display font-black text-white italic tracking-tighter">{{ stat.value }}</div>
          </div>
       </div>
    </div>

    <!-- Product Sections (Placeholders for now) -->
    <div class="space-y-8">
       <div class="flex items-center justify-between px-2">
          <h2 class="text-3xl font-display font-black text-dark-950 italic tracking-tighter">Yeni Fırsatlar</h2>
          <NuxtLink to="/products" class="text-xs font-black text-primary-600 uppercase tracking-widest hover:underline">Tümünü Gör</NuxtLink>
       </div>
       <div class="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-6">
          <div v-for="i in 5" :key="i" class="bg-gray-50 rounded-[2rem] h-[350px] animate-pulse" />
       </div>
    </div>
  </div>
</template>

<script setup lang="ts">
const { t } = useI18n();

const stats = [
  { label: 'Aktif Üye', value: '1.2K+' },
  { label: 'Takas Havuzu', value: '450+' },
  { label: 'Güvenli Takas', value: '%100' },
  { label: 'Yapay Zeka', value: 'Pro' },
];

const features = [
  { label: 'Hızlı İşlem', title: 'Acil Takas', icon: 'heroicons:bolt' },
  { label: 'Kurumsal', title: 'Ticari Partner', icon: 'heroicons:building-office-2' },
  { label: 'Güvenlik', title: 'Escrow Ödeme', icon: 'heroicons:shield-check' },
  { label: 'Analiz', title: 'Akıllı Eşleşme', icon: 'heroicons:presentation-chart-line' },
];
</script>
